import type { Billboard } from "../../componentTypes/billboard"
import type { Semantics } from "../semantics"

const billboard = (semantics: Semantics): Billboard => ({
  backgroundColor: semantics.color.background.base,
  fontFamily: semantics.fontFamily.base,
  paddingSmall: semantics.spacing.spaceMd,
  paddingMedium: semantics.spacing.spaceXl,
  paddingLarge: semantics.spacing.spaceXl,
  mediumMargin: semantics.spacing.spaceMd,
  largeMargin: semantics.spacing.spaceXl,
  buttonBorderWidth: semantics.borderWidth.md,
  buttonBorderStyle: "solid",
  buttonHoverBorderStyle: "dashed",
  buttonBorderRadius: "0.5rem",
  messageColor: semantics.color.text.interactive.navigation.primary.base,
  messageColorClickable: semantics.color.institutional.linkColor,
  clickableActiveBg: semantics.color.background.interactive.action.primary.active,
  clickableActiveText: semantics.color.text.onColor,
  messageFontSizeSmall: semantics.fontSize.textSm,
  messageFontSizeMedium: semantics.fontSize.textBase,
  messageFontSizeLarge: semantics.fontSize.textLg,
})
export default billboard
